# test_group_by.py
import pytest

# Adjust this import to match where group_by is defined
# from your_module import group_by


def group_by(items: list, key_fn) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


def test_group_by_happy_path_groups_items_by_key():
    items = ["apple", "apricot", "banana", "blueberry", "cherry"]

    result = group_by(items, lambda item: item[0])

    assert result == {
        "a": ["apple", "apricot"],
        "b": ["banana", "blueberry"],
        "c": ["cherry"],
    }


def test_group_by_preserves_order_within_each_group():
    items = [5, 2, 4, 1, 3, 6]

    result = group_by(items, lambda item: item % 2)

    assert result == {
        1: [5, 1, 3],
        0: [2, 4, 6],
    }


def test_group_by_empty_list_returns_empty_dict():
    result = group_by([], lambda item: item)

    assert result == {}


def test_group_by_all_items_same_key():
    items = [1, 2, 3]

    result = group_by(items, lambda item: "same")

    assert result == {
        "same": [1, 2, 3],
    }


def test_group_by_each_item_unique_key():
    items = ["a", "bb", "ccc"]

    result = group_by(items, lambda item: len(item))

    assert result == {
        1: ["a"],
        2: ["bb"],
        3: ["ccc"],
    }


def test_group_by_handles_none_items():
    items = [None, "hello", None, "world"]

    result = group_by(items, lambda item: item is None)

    assert result == {
        True: [None, None],
        False: ["hello", "world"],
    }


def test_group_by_handles_none_as_key():
    items = ["a", "b", "c"]

    result = group_by(items, lambda item: None)

    assert result == {
        None: ["a", "b", "c"],
    }


def test_group_by_with_objects():
    items = [
        {"name": "Alice", "role": "admin"},
        {"name": "Bob", "role": "user"},
        {"name": "Carol", "role": "admin"},
    ]

    result = group_by(items, lambda item: item["role"])

    assert result == {
        "admin": [
            {"name": "Alice", "role": "admin"},
            {"name": "Carol", "role": "admin"},
        ],
        "user": [
            {"name": "Bob", "role": "user"},
        ],
    }


def test_group_by_key_function_is_called_for_each_item():
    items = [1, 2, 3]
    calls = []

    def key_fn(item):
        calls.append(item)
        return item % 2

    result = group_by(items, key_fn)

    assert result == {
        1: [1, 3],
        0: [2],
    }
    assert calls == [1, 2, 3]


def test_group_by_raises_type_error_when_key_is_unhashable():
    items = [1, 2, 3]

    with pytest.raises(TypeError):
        group_by(items, lambda item: [item])


def test_group_by_propagates_exception_from_key_function():
    items = [1, 2, 0, 4]

    def key_fn(item):
        return 10 / item

    with pytest.raises(ZeroDivisionError):
        group_by(items, key_fn)


def test_group_by_raises_type_error_when_key_fn_is_not_callable():
    items = [1, 2, 3]

    with pytest.raises(TypeError):
        group_by(items, None)


def test_group_by_raises_type_error_when_items_is_none():
    with pytest.raises(TypeError):
        group_by(None, lambda item: item)
